import java.util.*;

class StockProfit {
    // Function to calculate the maximum profit with at most 2 transactions
    public int maxProfit(int[] prices, int n) {
        // 'ahead' stores future state, 'cur' stores current state
        int[][] ahead = new int[2][3];
        int[][] cur = new int[2][3];

        // Iterate from the last day to the first day (reverse order)
        for (int ind = n - 1; ind >= 0; ind--) {
            for (int buy = 0; buy <= 1; buy++) { // 0 = buy possible, 1 = sell possible
                for (int cap = 1; cap <= 2; cap++) { // At most 2 transactions
                    if (buy == 0) {
                        // Option 1: Skip buying, Option 2: Buy stock
                        cur[buy][cap] = Math.max(ahead[0][cap],
                                -prices[ind] + ahead[1][cap]);
                    } else {
                        // Option 1: Skip selling, Option 2: Sell stock
                        cur[buy][cap] = Math.max(ahead[1][cap],
                                prices[ind] + ahead[0][cap - 1]);
                    }
                }
            }
            // Move current state to ahead for the next iteration
            for (int i = 0; i < 2; i++) {
                System.arraycopy(cur[i], 0, ahead[i], 0, 3);
            }
        }

        return ahead[0][2]; // Maximum profit starting at day 0 with 2 transactions
    }

    public static void main(String[] args) {
        int[] prices = {3, 3, 5, 0, 0, 3, 1, 4};
        int n = prices.length;
        StockProfit sp = new StockProfit();
        System.out.println("The maximum profit that can be generated is " + sp.maxProfit(prices, n));
    }
}

